INSERT INTO jobs (id, title, description, department, responsibilities, qualifications, minimum_qualifications, benefits, salary_range, min_experience, max_experience, experience_level, employment_type, job_category, education, posted_date, expiry_date, number_of_positions, contact_email, contact_phone, promotion_type, state, city, district, address, remote_job, views, applicants, saved, liked, shared, resume, cover_letter, created_date, last_modified_date, status, company_id) VALUES ('51db3912-f05e-579b-86aa-2beb62db7949', 'Backend Engineer', 'Build backend services with Java and Spring Boot', 'Engineering', '["Own the delivery of backend engineer outcomes at Acme Tech, coordinating with stakeholders to translate business needs into well-scoped execution plans and measurable results.", "Collaborate across product, engineering and operations teams to improve delivery quality, documentation, observability and handoff discipline for the backend function.", "Continuously optimize workflows, remove recurring bottlenecks and contribute reusable standards that make the team faster, more predictable and easier to scale."]', '["1+ years of relevant hands-on experience with Java, Spring Boot and adjacent tooling used in modern product teams.", "Strong communication, structured problem-solving and the ability to work effectively with cross-functional stakeholders under changing priorities.", "Comfort interpreting requirements, documenting trade-offs and maintaining high execution quality across day-to-day delivery."]', '["Bachelor degree or equivalent practical experience.", "Working familiarity with Java, Spring Boot, PostgreSQL.", "Able to work in a fast-moving, collaborative environment with clear ownership."]', '["Hybrid working model, private health coverage and a transparent growth path at Acme Tech.", "Annual learning budget, modern equipment allowance and structured performance feedback every quarter.", "Team-based bonus, paid leave and support for professional certifications relevant to the role."]', '1200-2000', 0, 2, 'MIDDLE', 'FULL_TIME', 'ENGINEER', 'BACHELORS_DEGREE', '2026-05-25', '2026-07-09', 1, 'hr+acme-tech@careergraph.demo', '+84-28-1007-2007', 'paid', 'Ho Chi Minh', 'District 1', 'Ben Nghe', '12 Le Duan', false, 159, 0, 5, 2, 6, true, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, 'ACTIVE', 'ea0e6db0-697f-522c-b6ee-ddc950a5f1c2') ON CONFLICT (id) DO NOTHING;
