rtifications relevant to the role."]', '1500-2500', 1, 4, 'SENIOR', 'FULL_TIME', 'BUSINESS', 'BACHELORS_DEGREE', '2026-05-24', '2026-07-09', 2, 'hr+nova-solutions@careergraph.demo', '+84-28-1000-2000', 'free', 'Ho Chi Minh', 'District 1', 'Ben Nghe', '12 Le Duan', false, 93, 0, 4, 2, 3, true, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, 'ACTIVE', '80aeee7e-b127-5022-a1ba-31466f197a97') ON CONFLICT (id) DO NOTHING;
